-- Grammar lessons & Topics
TRUNCATE grammar_lessons RESTART IDENTITY CASCADE;
TRUNCATE topics RESTART IDENTITY CASCADE;
INSERT INTO grammar_lessons (title, level, icon, theory, questions) VALUES ('Present Simple', 'A1', '📘', 'Dùng để diễn tả thói quen, sự thật, lịch trình.

Cấu trúc:
✅ I/You/We/They + V (nguyên thể)
✅ He/She/It + V-s/es
✅ Phủ định: don''t / doesn''t + V
✅ Câu hỏi: Do/Does + S + V?

Ví dụ:
✅ She works every day.
✅ They don''t like coffee.
✅ Does he play football?', '[{"q": "She ___ to school every day.", "opts": ["go", "goes", "going", "gone"], "ans": 1, "exp": "He/She/It → thêm -s: go → goes"}, {"q": "They ___ coffee in the morning.", "opts": ["don''t drink", "doesn''t drink", "not drink", "no drink"], "ans": 0, "exp": "They dùng don''t + V nguyên thể"}, {"q": "___ he play football?", "opts": ["Do", "Does", "Is", "Has"], "ans": 1, "exp": "He/She/It → Does + S + V?"}, {"q": "The sun ___ in the east.", "opts": ["rise", "rising", "rises", "rose"], "ans": 2, "exp": "Sự thật: The sun (It) → rises"}, {"q": "We ___ English on Mondays.", "opts": ["study", "studies", "studying", "studied"], "ans": 0, "exp": "We + V nguyên thể: study"}, {"q": "My brother ___ not like vegetables.", "opts": ["do", "does", "is", "has"], "ans": 1, "exp": "My brother = He → does not"}, {"q": "How often ___ she exercise?", "opts": ["do", "does", "is", "has"], "ans": 1, "exp": "She → does + V?"}, {"q": "The train ___ at 8 am every day.", "opts": ["leave", "leaves", "leaving", "left"], "ans": 1, "exp": "The train (It) + V-s: leaves"}, {"q": "I ___ my teeth twice a day.", "opts": ["brush", "brushes", "brushing", "brushed"], "ans": 0, "exp": "I + V nguyên thể: brush"}, {"q": "Câu nào đúng?", "opts": ["She don''t work here.", "He works here.", "They works here.", "We works here."], "ans": 1, "exp": "He/She/It + V-s: He works here."}]'::jsonb);
INSERT INTO grammar_lessons (title, level, icon, theory, questions) VALUES ('To Be (am/is/are)', 'A1', '📗', 'Động từ ''to be'' có 3 dạng: am, is, are.

Quy tắc:
✅ I → am
✅ He/She/It → is
✅ You/We/They → are
✅ Phủ định: am not / isn''t / aren''t
✅ Câu hỏi: Am I? / Is he? / Are you?

Ví dụ:
✅ I am a student.
✅ She is happy today.
✅ They are at school.', '[{"q": "I ___ a teacher.", "opts": ["am", "is", "are", "be"], "ans": 0, "exp": "I + am"}, {"q": "She ___ very tired today.", "opts": ["am", "is", "are", "be"], "ans": 1, "exp": "She + is"}, {"q": "They ___ at home now.", "opts": ["am", "is", "are", "be"], "ans": 2, "exp": "They + are"}, {"q": "___ you ready?", "opts": ["Am", "Is", "Are", "Be"], "ans": 2, "exp": "You → Are you?"}, {"q": "He ___ not hungry.", "opts": ["am", "is", "are", "do"], "ans": 1, "exp": "He + is not (isn''t)"}, {"q": "The children ___ in the park.", "opts": ["am", "is", "are", "be"], "ans": 2, "exp": "Children (They) → are"}, {"q": "___ it cold outside?", "opts": ["Am", "Is", "Are", "Do"], "ans": 1, "exp": "It → Is it?"}, {"q": "We ___ from Vietnam.", "opts": ["am", "is", "are", "be"], "ans": 2, "exp": "We + are"}, {"q": "Câu nào sai?", "opts": ["I am fine.", "She are happy.", "He is tall.", "They are students."], "ans": 1, "exp": "She + is, không phải are → She is happy."}, {"q": "My parents ___ doctors.", "opts": ["am", "is", "are", "be"], "ans": 2, "exp": "My parents (They) → are"}]'::jsonb);
INSERT INTO grammar_lessons (title, level, icon, theory, questions) VALUES ('Articles (a/an/the)', 'A1', '📙', 'Mạo từ trong tiếng Anh:

✅ a + danh từ bắt đầu bằng phụ âm: a cat, a book
✅ an + danh từ bắt đầu bằng nguyên âm (a,e,i,o,u): an apple, an egg
✅ the = xác định (đã biết, duy nhất): the sun, the book I told you
✅ Không dùng mạo từ: tên riêng, ngôn ngữ, môn thể thao

Ví dụ:
✅ I have a dog.
✅ She is an engineer.
✅ The moon is bright tonight.', '[{"q": "I saw ___ elephant at the zoo.", "opts": ["a", "an", "the", "—"], "ans": 1, "exp": "elephant bắt đầu bằng nguyên âm e → an"}, {"q": "___ sun rises in the east.", "opts": ["A", "An", "The", "—"], "ans": 2, "exp": "Chỉ có một mặt trời, dùng the"}, {"q": "She is ___ doctor.", "opts": ["a", "an", "the", "—"], "ans": 0, "exp": "doctor bắt đầu bằng phụ âm d → a"}, {"q": "I play ___ football on weekends.", "opts": ["a", "an", "the", "—"], "ans": 3, "exp": "Môn thể thao không dùng mạo từ"}, {"q": "He has ___ umbrella.", "opts": ["a", "an", "the", "—"], "ans": 1, "exp": "umbrella bắt đầu bằng nguyên âm u → an"}, {"q": "Can you close ___ door?", "opts": ["a", "an", "the", "—"], "ans": 2, "exp": "Cả hai đều biết cái cửa nào → the"}, {"q": "She speaks ___ English very well.", "opts": ["a", "an", "the", "—"], "ans": 3, "exp": "Tên ngôn ngữ không dùng mạo từ"}, {"q": "I want to buy ___ new car.", "opts": ["a", "an", "the", "—"], "ans": 0, "exp": "Đề cập lần đầu, bắt đầu bằng phụ âm → a"}, {"q": "___ Amazon is the longest river in South America.", "opts": ["A", "An", "The", "—"], "ans": 2, "exp": "Tên sông dùng the"}, {"q": "He is ___ honest man.", "opts": ["a", "an", "the", "—"], "ans": 1, "exp": "honest phát âm bắt đầu bằng /ɒ/ (nguyên âm) → an"}]'::jsonb);
INSERT INTO grammar_lessons (title, level, icon, theory, questions) VALUES ('There is / There are', 'A1', '📒', 'Dùng để diễn tả sự tồn tại của người/vật.

✅ There is + danh từ số ít / không đếm được
✅ There are + danh từ số nhiều
✅ Phủ định: There isn''t / There aren''t
✅ Câu hỏi: Is there? / Are there?

Ví dụ:
✅ There is a book on the table.
✅ There are three cats in the garden.
✅ Is there a supermarket near here?', '[{"q": "There ___ a cat on the roof.", "opts": ["is", "are", "am", "be"], "ans": 0, "exp": "a cat = số ít → There is"}, {"q": "There ___ many students in the class.", "opts": ["is", "are", "am", "be"], "ans": 1, "exp": "many students = số nhiều → There are"}, {"q": "___ there a bank near here?", "opts": ["Is", "Are", "Am", "Do"], "ans": 0, "exp": "a bank = số ít → Is there?"}, {"q": "There ___ some water in the bottle.", "opts": ["is", "are", "am", "were"], "ans": 0, "exp": "water = không đếm được → There is"}, {"q": "There ___ any books on the shelf.", "opts": ["isn''t", "aren''t", "am not", "hasn''t"], "ans": 1, "exp": "books = số nhiều → There aren''t"}, {"q": "___ there any eggs in the fridge?", "opts": ["Is", "Are", "Am", "Do"], "ans": 1, "exp": "eggs = số nhiều → Are there?"}, {"q": "There ___ a problem with my phone.", "opts": ["is", "are", "am", "have"], "ans": 0, "exp": "a problem = số ít → There is"}, {"q": "There ___ two cinemas in my town.", "opts": ["is", "are", "am", "has"], "ans": 1, "exp": "two cinemas = số nhiều → There are"}, {"q": "There ___ much noise outside.", "opts": ["is", "are", "am", "were"], "ans": 0, "exp": "noise = không đếm được → There is"}, {"q": "Câu nào đúng?", "opts": ["There are a dog.", "There is three books.", "There is a chair.", "There am a pen."], "ans": 2, "exp": "a chair = số ít → There is a chair."}]'::jsonb);
INSERT INTO grammar_lessons (title, level, icon, theory, questions) VALUES ('Past Simple', 'A2', '📘', 'Dùng để diễn tả hành động đã hoàn thành trong quá khứ.

✅ Động từ có quy tắc: V + ed (work → worked)
✅ Động từ bất quy tắc: go → went, see → saw, eat → ate
✅ Phủ định: didn''t + V nguyên thể
✅ Câu hỏi: Did + S + V?
✅ Was/were = quá khứ của to be

Ví dụ:
✅ She visited her grandmother last weekend.
✅ I didn''t go to school yesterday.
✅ Did you see that film?', '[{"q": "She ___ to Paris last year.", "opts": ["go", "goes", "went", "gone"], "ans": 2, "exp": "go → went (bất quy tắc)"}, {"q": "I ___ a great movie last night.", "opts": ["see", "saw", "seen", "sees"], "ans": 1, "exp": "see → saw (bất quy tắc)"}, {"q": "They ___ play football yesterday.", "opts": ["don''t", "doesn''t", "didn''t", "weren''t"], "ans": 2, "exp": "Phủ định quá khứ: didn''t + V nguyên thể"}, {"q": "___ you enjoy the party?", "opts": ["Do", "Does", "Did", "Were"], "ans": 2, "exp": "Câu hỏi quá khứ: Did + S + V?"}, {"q": "He ___ very tired after work.", "opts": ["is", "was", "were", "be"], "ans": 1, "exp": "He + was (quá khứ của is)"}, {"q": "We ___ dinner at 7 pm yesterday.", "opts": ["have", "had", "has", "were have"], "ans": 1, "exp": "have → had (bất quy tắc)"}, {"q": "She ___ a letter to her friend.", "opts": ["write", "wrote", "written", "writes"], "ans": 1, "exp": "write → wrote (bất quy tắc)"}, {"q": "The children ___ at home last Sunday.", "opts": ["was", "were", "are", "is"], "ans": 1, "exp": "The children (They) + were"}, {"q": "I ___ walk to school. I took the bus.", "opts": ["don''t", "doesn''t", "didn''t", "wasn''t"], "ans": 2, "exp": "Phủ định quá khứ: didn''t + V nguyên thể"}, {"q": "What time ___ the meeting start?", "opts": ["do", "does", "did", "was"], "ans": 2, "exp": "Câu hỏi quá khứ: did + V?"}]'::jsonb);
INSERT INTO grammar_lessons (title, level, icon, theory, questions) VALUES ('Present Continuous', 'A2', '📗', 'Dùng để diễn tả hành động đang xảy ra ngay lúc nói, hoặc tạm thời.

✅ Cấu trúc: am/is/are + V-ing
✅ Thêm -ing: work → working, run → running, write → writing
✅ Phủ định: am/is/are + not + V-ing
✅ Câu hỏi: Am/Is/Are + S + V-ing?

Ví dụ:
✅ I am studying English now.
✅ She is not watching TV.
✅ Are they playing outside?', '[{"q": "She ___ a book right now.", "opts": ["read", "reads", "is reading", "was reading"], "ans": 2, "exp": "Đang xảy ra lúc này: is + reading"}, {"q": "They ___ football in the park.", "opts": ["play", "plays", "are playing", "were playing"], "ans": 2, "exp": "They + are playing"}, {"q": "I ___ for the bus at the moment.", "opts": ["wait", "am waiting", "is waiting", "waits"], "ans": 1, "exp": "I + am + V-ing: am waiting"}, {"q": "___ he working from home today?", "opts": ["Do", "Does", "Is", "Are"], "ans": 2, "exp": "He → Is he + V-ing?"}, {"q": "We ___ watch TV. We are studying.", "opts": ["aren''t", "isn''t", "don''t", "doesn''t"], "ans": 0, "exp": "We + aren''t + V-ing"}, {"q": "Look! The cat ___ on my chair.", "opts": ["sit", "sits", "is sitting", "was sitting"], "ans": 2, "exp": "Look! = đang xảy ra → is sitting"}, {"q": "She ___ her homework now.", "opts": ["do", "does", "is doing", "was doing"], "ans": 2, "exp": "is + doing (V-ing)"}, {"q": "He ___ swim → correct V-ing form?", "opts": ["swiming", "swimming", "swims", "swimmed"], "ans": 1, "exp": "swim kết thúc bằng -m, nhân đôi + ing: swimming"}, {"q": "What ___ you doing?", "opts": ["do", "does", "are", "is"], "ans": 2, "exp": "You → are you doing?"}, {"q": "Câu nào đúng?", "opts": ["She is cooks dinner.", "He are eating lunch.", "They is sleeping.", "I am listening to music."], "ans": 3, "exp": "I + am + V-ing → I am listening to music."}]'::jsonb);
INSERT INTO grammar_lessons (title, level, icon, theory, questions) VALUES ('Future Simple (will)', 'A2', '📙', 'Dùng để diễn tả quyết định tức thời, dự đoán, lời hứa.

✅ Cấu trúc: S + will + V (nguyên thể)
✅ Viết tắt: I''ll, she''ll, they''ll
✅ Phủ định: will not = won''t
✅ Câu hỏi: Will + S + V?

Ví dụ:
✅ I will call you later.
✅ She won''t be late.
✅ Will you help me?', '[{"q": "I ___ call you tomorrow.", "opts": ["will", "am going to", "would", "shall"], "ans": 0, "exp": "Quyết định tức thời / lời hứa → will"}, {"q": "She ___ not come to the party.", "opts": ["will", "won''t", "wouldn''t", "isn''t"], "ans": 1, "exp": "will not = won''t"}, {"q": "___ you help me with this?", "opts": ["Do", "Are", "Will", "Shall"], "ans": 2, "exp": "Will + S + V? cho câu hỏi tương lai"}, {"q": "It''s hot. I ___ open the window.", "opts": ["will", "am going to", "would", "shall"], "ans": 0, "exp": "Quyết định tức thời → will"}, {"q": "They ___ finish the project next week.", "opts": ["will", "would", "shall", "are"], "ans": 0, "exp": "Dự đoán tương lai → will"}, {"q": "I think it ___ rain tomorrow.", "opts": ["will", "would", "is", "shall"], "ans": 0, "exp": "Dự đoán với I think → will"}, {"q": "He ___ not be happy about this.", "opts": ["will", "won''t", "wouldn''t", "isn''t"], "ans": 1, "exp": "will not = won''t"}, {"q": "___ she be at the meeting?", "opts": ["Does", "Is", "Will", "Has"], "ans": 2, "exp": "Will + S + V?"}, {"q": "Don''t worry. I ___ help you.", "opts": ["will", "would", "am going to", "shall"], "ans": 0, "exp": "Lời hứa tức thời → will"}, {"q": "Câu nào dùng ''will'' sai?", "opts": ["I will goes to the park.", "She will come tomorrow.", "Will they arrive on time?", "He won''t be late."], "ans": 0, "exp": "will + V nguyên thể: will go (không phải goes)"}]'::jsonb);
INSERT INTO grammar_lessons (title, level, icon, theory, questions) VALUES ('be going to', 'A2', '📒', 'Dùng để diễn tả kế hoạch đã định sẵn hoặc dự đoán có bằng chứng.

✅ Cấu trúc: am/is/are + going to + V
✅ Phủ định: am/is/are + not + going to + V
✅ Câu hỏi: Am/Is/Are + S + going to + V?

Ví dụ:
✅ I am going to visit my friend this weekend.
✅ Look at those clouds — it is going to rain.
✅ Are you going to study tonight?', '[{"q": "She ___ going to study medicine.", "opts": ["am", "is", "are", "be"], "ans": 1, "exp": "She + is going to"}, {"q": "We ___ going to travel to Japan next year.", "opts": ["am", "is", "are", "be"], "ans": 2, "exp": "We + are going to"}, {"q": "Look at those clouds! It ___ going to rain.", "opts": ["am", "is", "are", "was"], "ans": 1, "exp": "It + is going to (bằng chứng có mây)"}, {"q": "___ they going to move to a new house?", "opts": ["Is", "Am", "Are", "Do"], "ans": 2, "exp": "They → Are they going to?"}, {"q": "He ___ not going to attend the meeting.", "opts": ["am", "is", "are", "has"], "ans": 1, "exp": "He + is not going to"}, {"q": "I ___ going to cook dinner tonight.", "opts": ["am", "is", "are", "be"], "ans": 0, "exp": "I + am going to"}, {"q": "They are going to ___ a new project.", "opts": ["starts", "started", "start", "starting"], "ans": 2, "exp": "going to + V nguyên thể: start"}, {"q": "She ___ going to be a doctor when she grows up.", "opts": ["am", "is", "are", "will"], "ans": 1, "exp": "She + is going to"}, {"q": "___ you going to watch the game tonight?", "opts": ["Is", "Am", "Are", "Do"], "ans": 2, "exp": "You → Are you going to?"}, {"q": "Câu nào đúng với be going to?", "opts": ["I going to travel.", "She is go to travel.", "They are going to travel.", "He are going to travel."], "ans": 2, "exp": "They + are going to + V: They are going to travel."}]'::jsonb);
INSERT INTO grammar_lessons (title, level, icon, theory, questions) VALUES ('Past Continuous', 'A2', '📕', 'Dùng để diễn tả hành động đang xảy ra tại một thời điểm trong quá khứ.

✅ Cấu trúc: was/were + V-ing
✅ Thường đi với Past Simple: While I was cooking, the phone rang.
✅ Phủ định: wasn''t / weren''t + V-ing
✅ Câu hỏi: Was/Were + S + V-ing?

Ví dụ:
✅ She was reading when I arrived.
✅ They were playing football at 5 pm.
✅ Was he working late last night?', '[{"q": "At 8pm last night, I ___ TV.", "opts": ["watch", "watches", "was watching", "am watching"], "ans": 2, "exp": "Đang xảy ra tại thời điểm cụ thể trong quá khứ → was watching"}, {"q": "They ___ football when it started to rain.", "opts": ["play", "played", "were playing", "are playing"], "ans": 2, "exp": "Hành động đang diễn ra (were playing) bị gián đoạn (started)"}, {"q": "___ she sleeping when you called?", "opts": ["Is", "Was", "Were", "Did"], "ans": 1, "exp": "She → Was she + V-ing?"}, {"q": "I ___ while she was cooking.", "opts": ["read", "reads", "was reading", "am reading"], "ans": 2, "exp": "Hai hành động song song: was reading"}, {"q": "The children ___ in the garden all afternoon.", "opts": ["play", "played", "were playing", "are playing"], "ans": 2, "exp": "Suốt buổi chiều → were playing"}, {"q": "He ___ not working when I arrived.", "opts": ["was", "were", "is", "did"], "ans": 0, "exp": "He + was not (wasn''t) working"}, {"q": "While I ___ a shower, the doorbell rang.", "opts": ["take", "took", "was taking", "am taking"], "ans": 2, "exp": "While + Past Continuous: was taking"}, {"q": "What ___ you doing at midnight?", "opts": ["do", "did", "was", "were"], "ans": 3, "exp": "You → were you doing?"}, {"q": "She ___ her homework when her mother came in.", "opts": ["do", "did", "was doing", "does"], "ans": 2, "exp": "Đang làm (was doing) khi bị gián đoạn"}, {"q": "Câu nào đúng?", "opts": ["They was playing tennis.", "She were sleeping.", "He was cooking dinner.", "I were reading."], "ans": 2, "exp": "He + was + V-ing: He was cooking dinner."}]'::jsonb);
INSERT INTO grammar_lessons (title, level, icon, theory, questions) VALUES ('Comparatives & Superlatives', 'A2', '📘', 'So sánh trong tiếng Anh:

✅ So sánh hơn (short adj): adj + er + than: taller than
✅ So sánh hơn (long adj): more + adj + than: more expensive than
✅ So sánh nhất (short): the + adj + est: the tallest
✅ So sánh nhất (long): the most + adj: the most beautiful
✅ Bất quy tắc: good→better→best, bad→worse→worst

Ví dụ:
✅ She is taller than her sister.
✅ This phone is more expensive than that one.
✅ He is the best student in the class.', '[{"q": "This bag is ___ than that one. (heavy)", "opts": ["more heavy", "heavier", "heaviest", "the heavier"], "ans": 1, "exp": "heavy → heavier (short adj, đổi y→i + er)"}, {"q": "She is the ___ student in the class. (smart)", "opts": ["more smart", "smarter", "smartest", "most smart"], "ans": 2, "exp": "Superlative: smart → the smartest"}, {"q": "This film is ___ than the book.", "opts": ["more interesting", "interestinger", "most interesting", "interestingest"], "ans": 0, "exp": "Long adj → more + adj + than"}, {"q": "He runs ___ than anyone in his team. (fast)", "opts": ["more fast", "fastest", "faster", "most fast"], "ans": 2, "exp": "fast → faster (short adj + er)"}, {"q": "That was ___ day of my life. (bad)", "opts": ["worse", "worst", "the worst", "the worse"], "ans": 2, "exp": "Superlative bất quy tắc: bad → the worst"}, {"q": "My English is getting ___. (good)", "opts": ["gooder", "more good", "better", "best"], "ans": 2, "exp": "Comparative bất quy tắc: good → better"}, {"q": "This is ___ restaurant in the city. (expensive)", "opts": ["more expensive", "expensiver", "the most expensive", "expensivest"], "ans": 2, "exp": "Long adj superlative: the most expensive"}, {"q": "He is ___ his brother. (tall)", "opts": ["taller than", "taller", "tallest", "more tall than"], "ans": 0, "exp": "So sánh hơn: tall → taller than"}, {"q": "Today is ___ than yesterday. (cold)", "opts": ["more cold", "colder", "coldest", "the coldest"], "ans": 1, "exp": "cold → colder (short adj + er)"}, {"q": "She is ___ person I know. (generous)", "opts": ["more generous", "generousest", "the most generous", "generouserst"], "ans": 2, "exp": "Long adj superlative: the most generous"}]'::jsonb);
INSERT INTO topics (title, level, icon, theory, questions) VALUES ('Food & Dining', 'A1', '🍽️', 'Từ vựng về đồ ăn và nhà hàng:

🔑 Từ vựng quan trọng:
• menu (thực đơn), order (gọi món), waiter/waitress (người phục vụ)
• bill/check (hóa đơn), delicious (ngon), portion (khẩu phần)
• sweet (ngọt), sour (chua), salty (mặn), spicy (cay), bitter (đắng)
• starter (khai vị), main course (món chính), dessert (tráng miệng)
• vegetarian (ăn chay), reservation (đặt bàn), tip (tiền boa)

✅ Hỏi nhà hàng: Can I have the menu, please?
✅ Gọi món: I would like the pasta, please.
✅ Hỏi giá: How much is this dish?', '[{"q": "A: Can I see the ___? B: Of course, here you are.", "opts": ["bill", "menu", "tip", "order"], "ans": 1, "exp": "menu = thực đơn, dùng để chọn món"}, {"q": "The food was amazing! It was absolutely ___.", "opts": ["bitter", "delicious", "sour", "salty"], "ans": 1, "exp": "delicious = ngon, dùng khi khen đồ ăn"}, {"q": "I don''t eat meat. I am ___.", "opts": ["hungry", "a waiter", "vegetarian", "a chef"], "ans": 2, "exp": "vegetarian = người ăn chay"}, {"q": "Could we have the ___, please? We want to pay.", "opts": ["menu", "order", "bill", "tip"], "ans": 2, "exp": "bill/check = hóa đơn thanh toán"}, {"q": "This soup is very ___. I need some water!", "opts": ["sweet", "bitter", "spicy", "cold"], "ans": 2, "exp": "spicy = cay, khiến cần uống nước"}, {"q": "The ___ came to take our order.", "opts": ["chef", "waiter", "customer", "manager"], "ans": 1, "exp": "waiter = người phục vụ tại bàn"}, {"q": "For ___, I would like chocolate cake.", "opts": ["starter", "main course", "dessert", "appetizer"], "ans": 2, "exp": "dessert = tráng miệng (cuối bữa)"}, {"q": "A: How would you like your steak? B: ___, please.", "opts": ["Delicious", "Well-done", "Spicy", "Sour"], "ans": 1, "exp": "Well-done = chín kỹ, cách yêu cầu nấu thịt"}, {"q": "We made a ___ for 7 pm at the Italian restaurant.", "opts": ["menu", "reservation", "order", "tip"], "ans": 2, "exp": "reservation = đặt chỗ/đặt bàn trước"}, {"q": "The lemon is very ___.", "opts": ["sweet", "salty", "sour", "spicy"], "ans": 2, "exp": "sour = chua, vị đặc trưng của chanh"}]'::jsonb);
INSERT INTO topics (title, level, icon, theory, questions) VALUES ('Home & Family', 'A1', '🏠', 'Từ vựng về ngôi nhà và gia đình:

🔑 Phòng trong nhà:
• bedroom (phòng ngủ), kitchen (nhà bếp), living room (phòng khách)
• bathroom (phòng tắm), dining room (phòng ăn), garage (nhà để xe)

🔑 Đồ đạc:
• sofa (ghế sofa), lamp (đèn), curtain (rèm cửa), wardrobe (tủ quần áo)

🔑 Quan hệ gia đình:
• grandparent (ông/bà), cousin (anh/chị/em họ), nephew (cháu trai)
• niece (cháu gái), uncle (chú/bác), aunt (cô/dì)

✅ Where do you live? — I live in a house with my family.
✅ How many bedrooms does your house have?', '[{"q": "We cook meals in the ___.", "opts": ["bedroom", "bathroom", "kitchen", "garage"], "ans": 2, "exp": "kitchen = nhà bếp, nơi nấu ăn"}, {"q": "My mother''s sister is my ___.", "opts": ["niece", "cousin", "aunt", "grandmother"], "ans": 2, "exp": "aunt = cô/dì (chị/em gái của bố hoặc mẹ)"}, {"q": "I sleep in my ___.", "opts": ["living room", "kitchen", "bathroom", "bedroom"], "ans": 3, "exp": "bedroom = phòng ngủ"}, {"q": "My brother''s son is my ___.", "opts": ["nephew", "niece", "cousin", "uncle"], "ans": 0, "exp": "nephew = cháu trai (con trai của anh/chị em)"}, {"q": "We sit on the ___ and watch TV.", "opts": ["lamp", "curtain", "sofa", "wardrobe"], "ans": 2, "exp": "sofa = ghế sofa"}, {"q": "The ___ is where we park our car.", "opts": ["bedroom", "garage", "kitchen", "bathroom"], "ans": 1, "exp": "garage = nhà để xe"}, {"q": "My parents'' parents are my ___.", "opts": ["cousins", "uncles", "grandparents", "aunts"], "ans": 2, "exp": "grandparents = ông bà"}, {"q": "We eat dinner in the ___ room.", "opts": ["living", "dining", "bath", "bed"], "ans": 1, "exp": "dining room = phòng ăn"}, {"q": "I close the ___ to keep the sun out.", "opts": ["lamp", "sofa", "curtain", "wardrobe"], "ans": 2, "exp": "curtain = rèm cửa, che nắng"}, {"q": "My father''s brother is my ___.", "opts": ["nephew", "cousin", "aunt", "uncle"], "ans": 3, "exp": "uncle = chú/bác (anh/em trai của bố hoặc mẹ)"}]'::jsonb);
INSERT INTO topics (title, level, icon, theory, questions) VALUES ('School & Learning', 'A2', '🏫', 'Từ vựng về trường học:

🔑 Từ vựng lớp học:
• textbook (sách giáo khoa), notebook (vở ghi), timetable (thời khóa biểu)
• assignment/homework (bài tập về nhà), grade/mark (điểm số)
• classmate (bạn học), teacher (giáo viên), principal (hiệu trưởng)

🔑 Môn học:
• Maths, Science, History, Geography, Literature, PE (Physical Education)

🔑 Hoạt động:
• attend (tham dự), revise (ôn bài), submit (nộp), fail/pass (trượt/đậu)

✅ What subjects do you study?
✅ When is your homework due?', '[{"q": "I need to open my ___ to find today''s lessons.", "opts": ["notebook", "timetable", "assignment", "grade"], "ans": 1, "exp": "timetable = thời khóa biểu, xem lịch học"}, {"q": "The teacher asked us to ___ our homework by Friday.", "opts": ["attend", "revise", "submit", "fail"], "ans": 2, "exp": "submit = nộp (bài tập)"}, {"q": "She got a high ___ on her exam.", "opts": ["textbook", "grade", "timetable", "classmate"], "ans": 1, "exp": "grade = điểm số"}, {"q": "I study ___ because I love numbers.", "opts": ["History", "Literature", "Maths", "Geography"], "ans": 2, "exp": "Maths = Toán học, liên quan đến số"}, {"q": "I need to ___ before the exam tomorrow.", "opts": ["fail", "submit", "attend", "revise"], "ans": 3, "exp": "revise = ôn tập lại bài"}, {"q": "My ___ lent me her notes from class.", "opts": ["principal", "classmate", "teacher", "grade"], "ans": 1, "exp": "classmate = bạn học cùng lớp"}, {"q": "Please write your answers in your ___.", "opts": ["textbook", "timetable", "notebook", "assignment"], "ans": 2, "exp": "notebook = vở ghi chép"}, {"q": "If you don''t study, you might ___ the exam.", "opts": ["pass", "submit", "attend", "fail"], "ans": 3, "exp": "fail = thi trượt"}, {"q": "We learn about countries and maps in ___.", "opts": ["Maths", "Science", "PE", "Geography"], "ans": 3, "exp": "Geography = Địa lý, học về đất nước và bản đồ"}, {"q": "The ___ is the head of the school.", "opts": ["classmate", "teacher", "principal", "grade"], "ans": 2, "exp": "principal = hiệu trưởng"}]'::jsonb);
INSERT INTO topics (title, level, icon, theory, questions) VALUES ('Shopping & Money', 'A2', '🛒', 'Từ vựng về mua sắm và tiền bạc:

🔑 Từ vựng cửa hàng:
• discount (giảm giá), receipt (hóa đơn/biên lai), refund (hoàn tiền)
• bargain (món hời), checkout (quầy thanh toán), cashier (thu ngân)
• fitting room (phòng thử đồ), price tag (nhãn giá), sale (đợt giảm giá)

🔑 Thanh toán:
• cash (tiền mặt), credit card (thẻ tín dụng), currency (tiền tệ)

✅ How much does it cost?
✅ Do you have this in a different size?
✅ Can I have a receipt, please?', '[{"q": "The jacket has a 30% ___. It was $100, now it''s $70.", "opts": ["refund", "receipt", "discount", "bargain"], "ans": 2, "exp": "discount = giảm giá (30% off)"}, {"q": "I''d like to try this dress on. Where is the ___?", "opts": ["checkout", "fitting room", "cashier", "receipt"], "ans": 1, "exp": "fitting room = phòng thử đồ"}, {"q": "She paid by ___ instead of cash.", "opts": ["price tag", "receipt", "credit card", "discount"], "ans": 2, "exp": "credit card = thẻ tín dụng"}, {"q": "This dress was only $5! What a ___!", "opts": ["refund", "bargain", "checkout", "cashier"], "ans": 1, "exp": "bargain = món hời, mua được giá rất tốt"}, {"q": "Please keep your ___ in case you want to return the item.", "opts": ["discount", "fitting room", "receipt", "price tag"], "ans": 2, "exp": "receipt = biên lai/hóa đơn mua hàng"}, {"q": "All items are at the ___ counter. Please pay there.", "opts": ["fitting room", "checkout", "bargain", "sale"], "ans": 1, "exp": "checkout = quầy thanh toán"}, {"q": "The store is having a big ___ — everything is 50% off!", "opts": ["refund", "price tag", "receipt", "sale"], "ans": 3, "exp": "sale = đợt giảm giá lớn"}, {"q": "The ___ on this shirt says it costs $25.", "opts": ["receipt", "price tag", "discount", "cashier"], "ans": 1, "exp": "price tag = nhãn giá gắn trên sản phẩm"}, {"q": "I want a ___ because the jacket was broken.", "opts": ["discount", "bargain", "refund", "price tag"], "ans": 2, "exp": "refund = hoàn tiền lại khi hàng lỗi"}, {"q": "The ___ scanned my items and told me the total.", "opts": ["cashier", "fitting room", "checkout", "receipt"], "ans": 0, "exp": "cashier = nhân viên thu ngân"}]'::jsonb);
INSERT INTO grammar_lessons (title, level, icon, theory, questions) VALUES ('Present Perfect', 'B1', '📘', 'Dùng để diễn tả kinh nghiệm, hành động vừa xong, hoặc tình huống liên quan đến hiện tại.

✅ Cấu trúc: have/has + past participle (V3)
✅ ever/never: hỏi/nói về kinh nghiệm
✅ already: đã làm rồi
✅ yet: trong câu phủ định/hỏi (chưa/chưa chưa?)
✅ just: vừa mới xong
✅ for/since: khoảng thời gian

Ví dụ:
✅ I have never been to Japan.
✅ She has already finished her homework.
✅ Have you eaten yet?', '[{"q": "She ___ never seen snow before.", "opts": ["have", "has", "had", "is"], "ans": 1, "exp": "She + has (Present Perfect)"}, {"q": "I ___ just finished my report.", "opts": ["have", "has", "had", "am"], "ans": 0, "exp": "I + have + just + V3"}, {"q": "Have you ___ to Paris?", "opts": ["go", "went", "been", "gone"], "ans": 2, "exp": "been = đã từng đến (và đã về); gone = đã đi (chưa về)"}, {"q": "He ___ already eaten lunch.", "opts": ["have", "has", "had", "is"], "ans": 1, "exp": "He + has + already + V3"}, {"q": "They haven''t arrived ___.", "opts": ["already", "just", "yet", "ever"], "ans": 2, "exp": "yet = dùng trong câu phủ định: haven''t ... yet"}, {"q": "I have lived here ___ 2010.", "opts": ["for", "since", "during", "ago"], "ans": 1, "exp": "since + mốc thời gian cụ thể: since 2010"}, {"q": "She has worked here ___ five years.", "opts": ["for", "since", "during", "in"], "ans": 0, "exp": "for + khoảng thời gian: for five years"}, {"q": "___ you ever tried sushi?", "opts": ["Did", "Do", "Have", "Has"], "ans": 2, "exp": "Câu hỏi kinh nghiệm: Have you ever + V3?"}, {"q": "This is the best film I ___ seen.", "opts": ["never", "ever", "have ever", "has ever"], "ans": 2, "exp": "This is the best ... I have ever seen"}, {"q": "Câu nào đúng?", "opts": ["She has went home.", "He have eaten.", "They has arrived.", "I have never tried it."], "ans": 3, "exp": "I + have + never + V3: I have never tried it."}]'::jsonb);
INSERT INTO grammar_lessons (title, level, icon, theory, questions) VALUES ('Past Perfect', 'B1', '📗', 'Dùng để diễn tả hành động xảy ra TRƯỚC một hành động khác trong quá khứ.

✅ Cấu trúc: had + past participle (V3)
✅ Phủ định: hadn''t + V3
✅ Thường đi với: before, after, when, already, by the time

Ví dụ:
✅ When I arrived, she had already left.
✅ He had never flown before that trip.
✅ By the time we got there, the film had started.', '[{"q": "When I arrived, she ___ already left.", "opts": ["has", "have", "had", "was"], "ans": 2, "exp": "Hành động xảy ra trước: had + V3"}, {"q": "He ___ never eaten sushi before his trip to Japan.", "opts": ["has", "have", "had", "did"], "ans": 2, "exp": "Trước một sự kiện quá khứ → had"}, {"q": "By the time we arrived, the party ___.", "opts": ["has ended", "have ended", "had ended", "is ended"], "ans": 2, "exp": "By the time + Past → had + V3"}, {"q": "She ___ (study) for 3 hours before she took a break.", "opts": ["has studied", "studied", "had studied", "was studying"], "ans": 2, "exp": "Trước khi nghỉ → had studied"}, {"q": "I couldn''t enter because I ___ my key.", "opts": ["lose", "lost", "had lost", "has lost"], "ans": 2, "exp": "Lý do trong quá khứ → had lost"}, {"q": "After they ___ dinner, they watched a film.", "opts": ["have", "had finished", "finish", "finished"], "ans": 1, "exp": "After + hành động trước (had + V3)"}, {"q": "___ she left before you arrived?", "opts": ["Has", "Have", "Had", "Did"], "ans": 2, "exp": "Câu hỏi Past Perfect: Had + S + V3?"}, {"q": "He told me he ___ the email already.", "opts": ["send", "sent", "had sent", "has sent"], "ans": 2, "exp": "Reported speech quá khứ → had + V3"}, {"q": "They ___ (not finish) the project when the boss arrived.", "opts": ["didn''t finish", "hadn''t finished", "hasn''t finished", "don''t finish"], "ans": 1, "exp": "Phủ định Past Perfect: hadn''t + V3"}, {"q": "I ___ that book before, so I chose another one.", "opts": ["read", "have read", "had read", "was reading"], "ans": 2, "exp": "Đã đọc trước đó → had read"}]'::jsonb);
INSERT INTO grammar_lessons (title, level, icon, theory, questions) VALUES ('Modal Verbs', 'B1', '📙', 'Động từ khiếm khuyết diễn tả khả năng, nghĩa vụ, lời khuyên.

✅ can/could: khả năng, yêu cầu lịch sự
✅ should/ought to: lời khuyên
✅ must/have to: nghĩa vụ bắt buộc
✅ mustn''t: cấm
✅ don''t have to: không cần thiết (không phải cấm)
✅ might/may: khả năng không chắc

Ví dụ:
✅ You should see a doctor.
✅ You must wear a seatbelt.
✅ She might be late today.', '[{"q": "You ___ smoke in this area. It is forbidden.", "opts": ["should", "must", "mustn''t", "don''t have to"], "ans": 2, "exp": "mustn''t = bị cấm, không được làm"}, {"q": "She ___ be tired after such a long journey.", "opts": ["must", "mustn''t", "should", "can"], "ans": 0, "exp": "must = suy luận logic (chắc chắn phải mệt)"}, {"q": "You ___ bring food. We have enough.", "opts": ["must", "mustn''t", "don''t have to", "should"], "ans": 2, "exp": "don''t have to = không cần thiết (không phải cấm)"}, {"q": "It ___ rain later. Take an umbrella.", "opts": ["must", "might", "should", "can''t"], "ans": 1, "exp": "might = có thể (không chắc)"}, {"q": "You ___ see a doctor if you feel unwell.", "opts": ["can", "must", "should", "might"], "ans": 2, "exp": "should = lời khuyên"}, {"q": "___ I open the window? It''s hot in here.", "opts": ["Should", "Must", "Could", "Might"], "ans": 2, "exp": "Could I...? = yêu cầu lịch sự"}, {"q": "Students ___ wear uniforms at this school.", "opts": ["should", "might", "must", "can"], "ans": 2, "exp": "must = bắt buộc, quy định"}, {"q": "She ___ speak three languages fluently.", "opts": ["must", "should", "can", "might"], "ans": 2, "exp": "can = khả năng hiện tại"}, {"q": "You look pale. You ___ rest today.", "opts": ["must", "can", "might", "should"], "ans": 3, "exp": "should = lời khuyên"}, {"q": "Câu nào đúng?", "opts": ["She can to swim.", "He musts go.", "They should leave early.", "I mights come."], "ans": 2, "exp": "Modal + V nguyên thể: should leave"}]'::jsonb);
INSERT INTO grammar_lessons (title, level, icon, theory, questions) VALUES ('Reported Speech', 'B1', '📒', 'Câu tường thuật: thuật lại lời nói của người khác.

✅ say vs tell: say (something) / tell someone
✅ Lùi thì khi tường thuật:
   present → past | past → past perfect
   will → would | can → could | am/is/are → was/were
✅ Đổi đại từ: I → he/she, my → his/her, you → I/he/she
✅ Đổi trạng từ: now → then, today → that day, here → there

Ví dụ:
✅ ''I am tired.'' → She said she was tired.
✅ ''I will call you.'' → He said he would call me.', '[{"q": "''I am happy.'' She said she ___ happy.", "opts": ["is", "was", "will be", "has been"], "ans": 1, "exp": "am → was (lùi thì trong reported speech)"}, {"q": "''I will come.'' He said he ___ come.", "opts": ["will", "would", "can", "shall"], "ans": 1, "exp": "will → would"}, {"q": "She ___ me she was leaving.", "opts": ["said", "told", "spoke", "talked"], "ans": 1, "exp": "tell + someone: She told me (không phải said me)"}, {"q": "''I can swim.'' He said he ___ swim.", "opts": ["can", "could", "might", "should"], "ans": 1, "exp": "can → could"}, {"q": "''We have finished.'' They said they ___ finished.", "opts": ["have", "has", "had", "were"], "ans": 2, "exp": "have → had (lùi thì)"}, {"q": "He said, ''I don''t know the answer.'' → He said he ___ the answer.", "opts": ["don''t know", "doesn''t know", "didn''t know", "hadn''t known"], "ans": 2, "exp": "don''t → didn''t (lùi từ present sang past)"}, {"q": "''Come here!'' → She ___ me to go there.", "opts": ["said", "told", "asked", "ordered"], "ans": 2, "exp": "Câu mệnh lệnh: told/asked + to V"}, {"q": "''Are you tired?'' → He asked ___ I was tired.", "opts": ["that", "if", "whether", "if/whether"], "ans": 3, "exp": "Câu hỏi Yes/No → asked if/whether"}, {"q": "She said, ''I saw him yesterday.'' → She said she ___ him the day before.", "opts": ["see", "saw", "had seen", "has seen"], "ans": 2, "exp": "saw → had seen (lùi thì)"}, {"q": "Câu nào đúng?", "opts": ["He told that he was ill.", "She said me she was busy.", "They said they would help.", "He told he was late."], "ans": 2, "exp": "say + (that): They said (that) they would help."}]'::jsonb);
INSERT INTO grammar_lessons (title, level, icon, theory, questions) VALUES ('Conditionals Type 0 & 1', 'B1', '📕', 'Câu điều kiện loại 0 và loại 1:

✅ Loại 0 (thực tế, sự thật):
   If + present simple, present simple
   VD: If you heat water to 100°C, it boils.

✅ Loại 1 (có thể xảy ra trong tương lai):
   If + present simple, will + V
   VD: If it rains, I will stay at home.

Lưu ý: Không dùng will sau ''if'' trong loại 1.', '[{"q": "If you ___ water, it evaporates. (heat)", "opts": ["heat", "will heat", "heated", "heats"], "ans": 0, "exp": "Loại 0: If + present simple, present simple"}, {"q": "If she studies hard, she ___ pass the exam.", "opts": ["will", "would", "can", "might"], "ans": 0, "exp": "Loại 1: If + present, will + V"}, {"q": "If I ___ free tomorrow, I''ll visit you.", "opts": ["am", "will be", "would be", "was"], "ans": 0, "exp": "Loại 1: Không dùng will sau ''if''"}, {"q": "Ice ___ if the temperature rises above 0°C.", "opts": ["melts", "will melt", "would melt", "melted"], "ans": 0, "exp": "Loại 0 (sự thật): present simple"}, {"q": "If it ___ tomorrow, we will cancel the picnic.", "opts": ["rains", "will rain", "rained", "would rain"], "ans": 0, "exp": "Loại 1: If + present (rains)"}, {"q": "If you press this button, the machine ___.", "opts": ["start", "starts", "will start", "would start"], "ans": 1, "exp": "Loại 0: If + present, present: starts"}, {"q": "She will be late if she ___ now.", "opts": ["doesn''t leave", "won''t leave", "didn''t leave", "wouldn''t leave"], "ans": 0, "exp": "Loại 1: doesn''t leave (present, phủ định)"}, {"q": "If you ___ exercise, your health improves. (do)", "opts": ["do", "will do", "would do", "did"], "ans": 0, "exp": "Loại 0: If + present, present"}, {"q": "If they ___ in time, we''ll start without them.", "opts": ["don''t arrive", "won''t arrive", "didn''t arrive", "wouldn''t arrive"], "ans": 0, "exp": "Loại 1: If + present simple"}, {"q": "Câu nào là loại 1 đúng?", "opts": ["If she will study, she passes.", "If he comes, I call you.", "If it rains, we will stay home.", "If they arrive, I would help."], "ans": 2, "exp": "Loại 1: If + present simple, will + V"}]'::jsonb);
INSERT INTO grammar_lessons (title, level, icon, theory, questions) VALUES ('MAKE vs DO', 'B1', '📘', 'MAKE và DO là hai động từ dễ nhầm:

✅ MAKE = tạo ra, sản xuất, gây ra
   make a cake, make a mistake, make friends, make a decision, make an effort, make a phone call, make noise

✅ DO = thực hiện, hoàn thành (hoạt động chung)
   do homework, do exercise, do the dishes, do business, do your best, do a course

Mẹo: Nếu tạo ra vật gì đó cụ thể → MAKE. Hoạt động nói chung → DO.', '[{"q": "She ___ a mistake in her report.", "opts": ["did", "made", "does", "makes"], "ans": 1, "exp": "make a mistake (mắc lỗi)"}, {"q": "He always ___ his homework after school.", "opts": ["makes", "does", "make", "do"], "ans": 1, "exp": "do homework (làm bài tập)"}, {"q": "Don''t ___ so much noise!", "opts": ["do", "make", "did", "made"], "ans": 1, "exp": "make noise (gây ồn ào)"}, {"q": "She ___ exercise every morning.", "opts": ["makes", "does", "made", "did"], "ans": 1, "exp": "do exercise (tập thể dục)"}, {"q": "Can you ___ me a favour?", "opts": ["do", "make", "did", "made"], "ans": 1, "exp": "do a favour (giúp đỡ ai)"}, {"q": "I ___ a phone call to my mother.", "opts": ["did", "made", "do", "make"], "ans": 1, "exp": "make a phone call (gọi điện)"}, {"q": "They ___ the dishes after dinner.", "opts": ["made", "make", "did", "do"], "ans": 2, "exp": "do the dishes (rửa bát)"}, {"q": "She ___ friends easily at her new school.", "opts": ["did", "does", "made", "makes"], "ans": 2, "exp": "make friends (kết bạn)"}, {"q": "He ___ a course in digital marketing.", "opts": ["made", "makes", "did", "does"], "ans": 2, "exp": "do a course (học một khoá)"}, {"q": "Let''s ___ a decision before it''s too late.", "opts": ["do", "did", "make", "made"], "ans": 2, "exp": "make a decision (đưa ra quyết định)"}]'::jsonb);
INSERT INTO grammar_lessons (title, level, icon, theory, questions) VALUES ('TAKE Collocations', 'B1', '📗', 'TAKE hay đi với các danh từ sau:

✅ take a break (nghỉ giải lao)
✅ take a photo (chụp ảnh)
✅ take notes (ghi chép)
✅ take an exam/test (thi/kiểm tra)
✅ take part in (tham gia vào)
✅ take turns (thay phiên nhau)
✅ take care of (chăm sóc)
✅ take place (diễn ra)
✅ take off (cởi ra; cất cánh)
✅ take time (mất thời gian)', '[{"q": "Let''s ___ a break. We''ve been working for 3 hours.", "opts": ["do", "make", "take", "get"], "ans": 2, "exp": "take a break = nghỉ giải lao"}, {"q": "The conference ___ place in Hanoi last week.", "opts": ["did", "made", "took", "had"], "ans": 2, "exp": "take place = diễn ra (sự kiện)"}, {"q": "Please ___ notes during the lecture.", "opts": ["do", "make", "take", "write"], "ans": 2, "exp": "take notes = ghi chép"}, {"q": "She is going to ___ an exam tomorrow.", "opts": ["do", "make", "take", "have"], "ans": 2, "exp": "take an exam = dự thi"}, {"q": "Who will ___ care of the dog when you travel?", "opts": ["do", "make", "take", "get"], "ans": 2, "exp": "take care of = chăm sóc"}, {"q": "They ___ turns driving on the long journey.", "opts": ["did", "made", "took", "had"], "ans": 2, "exp": "take turns = thay phiên nhau"}, {"q": "Remember to ___ off your shoes at the door.", "opts": ["do", "make", "take", "put"], "ans": 2, "exp": "take off = cởi ra (giày dép)"}, {"q": "Learning a new language ___ a lot of time.", "opts": ["does", "makes", "takes", "has"], "ans": 2, "exp": "take time = mất nhiều thời gian"}, {"q": "Can I ___ a photo of you?", "opts": ["do", "make", "take", "get"], "ans": 2, "exp": "take a photo = chụp ảnh"}, {"q": "Over 200 students ___ part in the competition.", "opts": ["did", "made", "took", "had"], "ans": 2, "exp": "take part in = tham gia"}]'::jsonb);
INSERT INTO grammar_lessons (title, level, icon, theory, questions) VALUES ('HAVE Collocations', 'B1', '📙', 'HAVE hay đi với các danh từ sau:

✅ have breakfast/lunch/dinner (ăn sáng/trưa/tối)
✅ have a meeting (họp)
✅ have a conversation (nói chuyện)
✅ have fun (vui vẻ)
✅ have a rest (nghỉ ngơi)
✅ have a look (nhìn qua)
✅ have a shower/bath (tắm)
✅ have trouble/difficulty (gặp khó khăn)
✅ have an argument (cãi nhau)
✅ have a good time (có thời gian vui vẻ)', '[{"q": "I always ___ breakfast at 7 am.", "opts": ["do", "make", "take", "have"], "ans": 3, "exp": "have breakfast = ăn sáng"}, {"q": "We ___ a meeting every Monday morning.", "opts": ["do", "make", "take", "have"], "ans": 3, "exp": "have a meeting = họp"}, {"q": "Did you ___ fun at the party?", "opts": ["do", "make", "take", "have"], "ans": 3, "exp": "have fun = vui vẻ"}, {"q": "Can I ___ a look at your report?", "opts": ["do", "make", "take", "have"], "ans": 3, "exp": "have a look = nhìn qua, xem qua"}, {"q": "She is going to ___ a rest after lunch.", "opts": ["do", "make", "take", "have"], "ans": 3, "exp": "have a rest = nghỉ ngơi"}, {"q": "They ___ an argument about money.", "opts": ["did", "made", "took", "had"], "ans": 3, "exp": "have an argument = cãi nhau"}, {"q": "I ___ a shower every morning.", "opts": ["do", "make", "take", "have"], "ans": 3, "exp": "have a shower = tắm (vòi hoa sen)"}, {"q": "She ___ trouble sleeping because of the noise.", "opts": ["does", "makes", "takes", "has"], "ans": 3, "exp": "have trouble = gặp khó khăn"}, {"q": "We ___ a great time at the festival!", "opts": ["did", "made", "took", "had"], "ans": 3, "exp": "have a great time = có khoảng thời gian tuyệt vời"}, {"q": "He ___ a long conversation with his boss today.", "opts": ["did", "made", "took", "had"], "ans": 3, "exp": "have a conversation = nói chuyện"}]'::jsonb);
INSERT INTO grammar_lessons (title, level, icon, theory, questions) VALUES ('Passive Voice', 'B2', '📘', 'Bị động nhấn mạnh vào hành động hoặc đối tượng chịu tác động.

✅ Cấu trúc: be + past participle (V3)
✅ Các thì:
   Present: is/are + V3 → English is spoken here.
   Past: was/were + V3 → The letter was written by her.
   Future: will be + V3
   Present Perfect: has/have been + V3
✅ By + tác nhân (có thể bỏ qua nếu không quan trọng)

Ví dụ:
✅ The report is written by the manager.
✅ Coffee is grown in Vietnam.', '[{"q": "English ___ all over the world. (speak)", "opts": ["speaks", "is spoken", "was spoken", "has spoken"], "ans": 1, "exp": "Bị động hiện tại: is + spoken (V3)"}, {"q": "The letter ___ by my mother yesterday. (write)", "opts": ["wrote", "was written", "is written", "written"], "ans": 1, "exp": "Bị động quá khứ: was + written (V3)"}, {"q": "The project ___ by next Friday. (finish)", "opts": ["will finish", "will be finished", "is finished", "finished"], "ans": 1, "exp": "Bị động tương lai: will be + V3"}, {"q": "The thief ___ by the police. (catch)", "opts": ["caught", "was caught", "has caught", "catch"], "ans": 1, "exp": "Bị động quá khứ: was + caught (V3)"}, {"q": "The bridge ___ in 1990. (build)", "opts": ["built", "was built", "has been built", "builds"], "ans": 1, "exp": "Bị động quá khứ: was built"}, {"q": "Three people ___ in the accident. (injure)", "opts": ["injured", "were injured", "injure", "are injuring"], "ans": 1, "exp": "Bị động quá khứ, số nhiều: were injured"}, {"q": "A new hospital ___ in our city. (build — present perfect)", "opts": ["built", "was built", "has been built", "is building"], "ans": 2, "exp": "Present Perfect bị động: has been built"}, {"q": "Rice ___ in many Asian countries. (grow — present)", "opts": ["grows", "is grown", "was grown", "growing"], "ans": 1, "exp": "Bị động hiện tại: is grown"}, {"q": "Đổi sang bị động: ''They cancelled the flight.''", "opts": ["The flight cancelled.", "The flight was cancelled.", "The flight is cancelled.", "The flight has cancelled."], "ans": 1, "exp": "They cancelled → The flight was cancelled (bị động quá khứ)"}, {"q": "The results ___ tomorrow. (announce)", "opts": ["announce", "will announce", "will be announced", "are announced"], "ans": 2, "exp": "Bị động tương lai: will be announced"}]'::jsonb);
INSERT INTO grammar_lessons (title, level, icon, theory, questions) VALUES ('Relative Clauses', 'B2', '📗', 'Mệnh đề quan hệ bổ sung thông tin cho danh từ:

✅ who = chỉ người: The man who called is my boss.
✅ which = chỉ vật/động vật: The book which I bought is great.
✅ that = người hoặc vật (informal): The car that I drive is old.
✅ whose = sở hữu: The girl whose bag was stolen called the police.
✅ where = chỉ nơi chốn: The city where I grew up is beautiful.
✅ Xác định (defining): không có dấu phẩy — thiếu thì mất nghĩa
✅ Không xác định (non-defining): có dấu phẩy — thêm thông tin phụ', '[{"q": "The woman ___ works here is very kind.", "opts": ["which", "whose", "who", "where"], "ans": 2, "exp": "who = đại từ quan hệ chỉ người"}, {"q": "This is the book ___ I told you about.", "opts": ["who", "whose", "where", "which"], "ans": 3, "exp": "which = chỉ vật"}, {"q": "The city ___ I was born has changed a lot.", "opts": ["who", "which", "where", "whose"], "ans": 2, "exp": "where = chỉ nơi chốn"}, {"q": "The student ___ bag was stolen was very upset.", "opts": ["who", "which", "where", "whose"], "ans": 3, "exp": "whose = sở hữu (túi của học sinh đó)"}, {"q": "She is the scientist ___ discovered the vaccine.", "opts": ["which", "whose", "where", "who"], "ans": 3, "exp": "who = người (the scientist)"}, {"q": "The hotel ___ we stayed was excellent.", "opts": ["who", "which", "whose", "where"], "ans": 3, "exp": "where = chỉ nơi chốn (khách sạn)"}, {"q": "London, ___ is the capital of England, has a lot of museums.", "opts": ["who", "which", "where", "whose"], "ans": 1, "exp": "Non-defining: which (chỉ vật/thành phố)"}, {"q": "I met a man ___ father is a famous actor.", "opts": ["who", "which", "whose", "where"], "ans": 2, "exp": "whose = cha của người đàn ông đó"}, {"q": "That''s the restaurant ___ we had our first date.", "opts": ["who", "which", "whose", "where"], "ans": 3, "exp": "where = nơi chốn"}, {"q": "Câu nào đúng?", "opts": ["The car who I drive is red.", "The woman which called is my sister.", "The house where I live is old.", "The man whose I met is kind."], "ans": 2, "exp": "where = nơi chốn: The house where I live."}]'::jsonb);
INSERT INTO grammar_lessons (title, level, icon, theory, questions) VALUES ('Conditionals Type 2 & 3', 'B2', '📙', 'Câu điều kiện loại 2 và loại 3:

✅ Loại 2 (không có thật ở hiện tại):
   If + past simple, would + V
   VD: If I had a lot of money, I would travel the world.

✅ Loại 3 (không có thật trong quá khứ, hối tiếc):
   If + past perfect, would have + V3
   VD: If she had studied harder, she would have passed.

Lưu ý: ''were'' thay ''was'' sau if trong loại 2 (formal).', '[{"q": "If I ___ a bird, I would fly to you. (be)", "opts": ["am", "was/were", "had been", "will be"], "ans": 1, "exp": "Loại 2: If + past simple (were/was)"}, {"q": "If she had studied harder, she ___ the exam.", "opts": ["will pass", "would pass", "would have passed", "had passed"], "ans": 2, "exp": "Loại 3: would have + V3"}, {"q": "If I won the lottery, I ___ a big house.", "opts": ["buy", "will buy", "would buy", "would have bought"], "ans": 2, "exp": "Loại 2: would + V nguyên thể"}, {"q": "If he ___ earlier, he wouldn''t have missed the train.", "opts": ["left", "had left", "would leave", "leaves"], "ans": 1, "exp": "Loại 3: If + past perfect"}, {"q": "What ___ you do if you saw a ghost?", "opts": ["will", "would", "do", "did"], "ans": 1, "exp": "Loại 2: What would you do if + past?"}, {"q": "If they ___ the map, they wouldn''t have got lost.", "opts": ["check", "checked", "had checked", "would check"], "ans": 2, "exp": "Loại 3: If + had + V3"}, {"q": "If I ___ you, I would accept the offer.", "opts": ["am", "was", "were", "had been"], "ans": 2, "exp": "Loại 2: If I were you... (formal)"}, {"q": "She ___ happier if she had a better job.", "opts": ["will be", "would be", "would have been", "was"], "ans": 1, "exp": "Loại 2: would + V"}, {"q": "Đây là câu điều kiện loại mấy? ''If I had known, I would have called.''", "opts": ["Loại 0", "Loại 1", "Loại 2", "Loại 3"], "ans": 3, "exp": "If + past perfect + would have + V3 = Loại 3"}, {"q": "If the weather ___ better, we would go hiking. (be)", "opts": ["is", "was/were", "had been", "will be"], "ans": 1, "exp": "Loại 2: If + past simple"}]'::jsonb);
INSERT INTO grammar_lessons (title, level, icon, theory, questions) VALUES ('Wish / If only', 'B2', '📒', 'Wish và If only diễn tả ước muốn hoặc hối tiếc:

✅ Ước muốn hiện tại (khác thực tế):
   wish/if only + past simple
   VD: I wish I were taller.

✅ Hối tiếc về quá khứ:
   wish/if only + past perfect
   VD: I wish I had studied harder.

✅ Ước muốn về tương lai (mong ai đó thay đổi):
   wish + would + V
   VD: I wish she would stop smoking.', '[{"q": "I wish I ___ taller. (be) — ước muốn hiện tại", "opts": ["am", "was/were", "had been", "will be"], "ans": 1, "exp": "Ước muốn hiện tại: wish + past simple"}, {"q": "She wishes she ___ harder at school. (study) — hối tiếc", "opts": ["studies", "studied", "had studied", "would study"], "ans": 2, "exp": "Hối tiếc quá khứ: wish + past perfect"}, {"q": "If only he ___ so rude! — ước muốn ai thay đổi", "opts": ["isn''t", "wasn''t", "wouldn''t be", "won''t be"], "ans": 2, "exp": "Wish/If only + would + V → mong ai thay đổi"}, {"q": "I wish I ___ speak Japanese. (can)", "opts": ["can", "could", "would", "might"], "ans": 1, "exp": "Ước muốn hiện tại: wish + could (quá khứ của can)"}, {"q": "If only we ___ the last bus! (not miss)", "opts": ["don''t miss", "didn''t miss", "hadn''t missed", "wouldn''t miss"], "ans": 2, "exp": "Hối tiếc quá khứ: if only + hadn''t + V3"}, {"q": "She wishes she ___ to the party last night.", "opts": ["goes", "went", "had gone", "would go"], "ans": 2, "exp": "Hối tiếc quá khứ: wish + had + V3"}, {"q": "I wish it ___ raining. It has been raining for days.", "opts": ["stops", "stopped", "would stop", "had stopped"], "ans": 2, "exp": "Ước muốn thay đổi: wish + would + V"}, {"q": "If only I ___ the answer! (know) — hiện tại", "opts": ["know", "knew", "had known", "would know"], "ans": 1, "exp": "Ước muốn hiện tại: if only + past simple"}, {"q": "He wishes he ___ that car. (not buy) — hối tiếc quá khứ", "opts": ["doesn''t buy", "didn''t buy", "hadn''t bought", "wouldn''t buy"], "ans": 2, "exp": "Hối tiếc: wish + hadn''t + V3"}, {"q": "''I wish I were rich.'' Câu này diễn tả điều gì?", "opts": ["Hối tiếc quá khứ", "Ước muốn hiện tại (khác thực tế)", "Ước muốn tương lai", "Dự đoán tương lai"], "ans": 1, "exp": "wish + past simple = ước muốn hiện tại nhưng không có thật"}]'::jsonb);
INSERT INTO grammar_lessons (title, level, icon, theory, questions) VALUES ('Phrasal Verbs', 'B2', '📕', 'Cụm động từ (Phrasal Verbs) thường gặp:

✅ give up: từ bỏ
✅ look after: chăm sóc
✅ turn on/off: bật/tắt
✅ put off: trì hoãn
✅ carry on: tiếp tục
✅ break down: hỏng (máy móc); sụp đổ (tâm lý)
✅ pick up: đón; nhặt lên; học được
✅ set up: thành lập; thiết lập
✅ go through: trải qua; xem qua
✅ run out of: hết (không còn nữa)', '[{"q": "Don''t ___ up! You''re almost there.", "opts": ["turn", "give", "put", "break"], "ans": 1, "exp": "give up = từ bỏ"}, {"q": "She ___ after her younger siblings every day.", "opts": ["looks", "turns", "puts", "carries"], "ans": 0, "exp": "look after = chăm sóc"}, {"q": "Can you ___ on the lights? It''s dark.", "opts": ["give", "put", "turn", "break"], "ans": 2, "exp": "turn on = bật (đèn, máy móc)"}, {"q": "The meeting has been ___ off until next week.", "opts": ["given", "turned", "put", "carried"], "ans": 2, "exp": "put off = trì hoãn"}, {"q": "Please ___ on with your work. Don''t stop.", "opts": ["give", "look", "turn", "carry"], "ans": 3, "exp": "carry on = tiếp tục"}, {"q": "My car ___ down on the motorway.", "opts": ["gave", "looked", "turned", "broke"], "ans": 3, "exp": "break down = hỏng, không chạy được"}, {"q": "I''ll ___ you up at the airport at 6 am.", "opts": ["give", "pick", "set", "put"], "ans": 1, "exp": "pick up = đón (ai đó)"}, {"q": "They ___ up a new company last year.", "opts": ["gave", "picked", "set", "turned"], "ans": 2, "exp": "set up = thành lập"}, {"q": "We have ___ out of coffee. Can you buy some?", "opts": ["given", "broken", "run", "turned"], "ans": 2, "exp": "run out of = hết (không còn)"}, {"q": "He ___ through a very difficult time last year.", "opts": ["gave", "went", "set", "carried"], "ans": 1, "exp": "go through = trải qua"}]'::jsonb);
INSERT INTO topics (title, level, icon, theory, questions) VALUES ('Travel & Transport', 'B1', '✈️', 'Từ vựng về du lịch và phương tiện:

🔑 Sân bay:
• boarding pass (thẻ lên máy bay), departure (khởi hành), arrival (đến nơi)
• customs (hải quan), check-in (làm thủ tục), baggage claim (nhận hành lý)

🔑 Khách sạn:
• reservation (đặt phòng), check-in/check-out, single/double room

🔑 Phương tiện:
• itinerary (lịch trình), transit (quá cảnh), landmark (địa danh nổi tiếng)
• sightseeing (tham quan), accommodation (chỗ ở), delay (trễ)

✅ I''d like to book a room for two nights.
✅ Can you tell me how to get to the museum?', '[{"q": "You need your ___ to board the plane.", "opts": ["itinerary", "boarding pass", "customs", "transit"], "ans": 1, "exp": "boarding pass = thẻ lên máy bay"}, {"q": "The flight was delayed. We had to wait 2 hours for our ___.", "opts": ["arrival", "boarding pass", "customs", "accommodation"], "ans": 0, "exp": "arrival = giờ đến nơi"}, {"q": "We made a hotel ___ three weeks in advance.", "opts": ["sightseeing", "landmark", "reservation", "transit"], "ans": 2, "exp": "reservation = đặt phòng/đặt chỗ"}, {"q": "The Eiffel Tower is a famous ___ in Paris.", "opts": ["transit", "accommodation", "landmark", "itinerary"], "ans": 2, "exp": "landmark = địa danh nổi tiếng"}, {"q": "You must go through ___ when you enter a new country.", "opts": ["boarding pass", "sightseeing", "accommodation", "customs"], "ans": 3, "exp": "customs = hải quan"}, {"q": "The trip ___ was: Day 1 Paris, Day 2 Lyon, Day 3 Nice.", "opts": ["accommodation", "itinerary", "transit", "delay"], "ans": 1, "exp": "itinerary = lịch trình chuyến đi"}, {"q": "We spent the afternoon ___ — visiting museums and parks.", "opts": ["sightseeing", "transiting", "checking-in", "boarding"], "ans": 0, "exp": "sightseeing = tham quan"}, {"q": "Our flight has a 2-hour ___ in Dubai.", "opts": ["delay", "transit", "arrival", "boarding"], "ans": 1, "exp": "transit = quá cảnh (dừng giữa đường)"}, {"q": "The hotel ___ was comfortable. We stayed 3 nights.", "opts": ["landmark", "sightseeing", "itinerary", "accommodation"], "ans": 3, "exp": "accommodation = chỗ ở"}, {"q": "A: Excuse me, how do I get to the station? B: Take bus 12. It''s a direct ___.", "opts": ["transit", "route", "landmark", "boarding"], "ans": 1, "exp": "route = tuyến đường"}]'::jsonb);
INSERT INTO topics (title, level, icon, theory, questions) VALUES ('Work & Career', 'B1', '💼', 'Từ vựng về công việc:

🔑 Xin việc:
• resume/CV (hồ sơ xin việc), cover letter (thư xin việc), interview (phỏng vấn)
• applicant (ứng viên), qualification (bằng cấp), reference (người giới thiệu)

🔑 Nơi làm việc:
• colleague (đồng nghiệp), supervisor (cấp trên), deadline (hạn chót)
• promotion (thăng chức), salary (lương tháng), benefits (phúc lợi)
• remote work (làm việc từ xa), performance (hiệu suất)

✅ I have an interview for a marketing position tomorrow.
✅ Could you tell me about the salary and benefits?', '[{"q": "She sent her ___ and cover letter to five companies.", "opts": ["interview", "salary", "resume", "deadline"], "ans": 2, "exp": "resume/CV = hồ sơ xin việc"}, {"q": "The project ___ is Friday. We must finish by then.", "opts": ["salary", "deadline", "promotion", "colleague"], "ans": 1, "exp": "deadline = hạn chót"}, {"q": "He got a ___ and now manages a team of 10.", "opts": ["salary", "benefits", "promotion", "deadline"], "ans": 2, "exp": "promotion = thăng chức"}, {"q": "My ___ include health insurance and free gym.", "opts": ["salary", "benefits", "qualifications", "deadline"], "ans": 1, "exp": "benefits = phúc lợi (ngoài lương)"}, {"q": "I work from home three days a week — I do ___ work.", "opts": ["remote", "salary", "interview", "promotion"], "ans": 0, "exp": "remote work = làm việc từ xa"}, {"q": "She is very skilled and has great ___.", "opts": ["deadlines", "qualifications", "colleagues", "salaries"], "ans": 1, "exp": "qualifications = bằng cấp, kỹ năng"}, {"q": "My ___ at work are very helpful and friendly.", "opts": ["supervisors", "colleagues", "applicants", "references"], "ans": 1, "exp": "colleagues = đồng nghiệp"}, {"q": "My ___ reviewed my work and gave me feedback.", "opts": ["colleague", "applicant", "supervisor", "reference"], "ans": 2, "exp": "supervisor = cấp trên, người giám sát"}, {"q": "His annual ___ is $50,000.", "opts": ["promotion", "benefit", "salary", "deadline"], "ans": 2, "exp": "salary = lương (thường tính hàng năm hoặc tháng)"}, {"q": "A: Did you get the job? B: I have a second ___ next Monday.", "opts": ["resume", "deadline", "interview", "salary"], "ans": 2, "exp": "interview = buổi phỏng vấn"}]'::jsonb);
INSERT INTO topics (title, level, icon, theory, questions) VALUES ('Health & Body', 'B1', '🏥', 'Từ vựng về sức khỏe:

🔑 Triệu chứng:
• symptom (triệu chứng), fever (sốt), cough (ho), headache (đau đầu)
• sore throat (đau họng), rash (phát ban), dizzy (chóng mặt)

🔑 Khám bệnh:
• prescription (đơn thuốc), pharmacy (hiệu thuốc), diagnosis (chẩn đoán)
• treatment (điều trị), dosage (liều lượng), surgery (phẫu thuật)
• allergy (dị ứng), recovery (hồi phục)

✅ I have a terrible headache and a fever.
✅ The doctor prescribed some antibiotics.
✅ Take this medicine twice a day after meals.', '[{"q": "She has a high ___. Her temperature is 39°C.", "opts": ["cough", "symptom", "fever", "rash"], "ans": 2, "exp": "fever = sốt cao"}, {"q": "The doctor gave me a ___ for antibiotics.", "opts": ["dosage", "prescription", "diagnosis", "surgery"], "ans": 1, "exp": "prescription = đơn thuốc do bác sĩ kê"}, {"q": "I''m ___ to peanuts — they make me very ill.", "opts": ["allergic", "dizzy", "recovering", "diagnosed"], "ans": 0, "exp": "allergic to = dị ứng với"}, {"q": "After the accident, she needed ___.", "opts": ["a dosage", "a prescription", "a symptom", "surgery"], "ans": 3, "exp": "surgery = phẫu thuật"}, {"q": "The doctor''s ___ was that I had a virus.", "opts": ["treatment", "prescription", "diagnosis", "dosage"], "ans": 2, "exp": "diagnosis = chẩn đoán của bác sĩ"}, {"q": "He felt ___ and nearly fainted.", "opts": ["allergic", "dizzy", "recovering", "coughing"], "ans": 1, "exp": "dizzy = chóng mặt"}, {"q": "Go to the ___ to buy the medicine.", "opts": ["hospital", "pharmacy", "clinic", "surgery"], "ans": 1, "exp": "pharmacy = hiệu thuốc, nhà thuốc"}, {"q": "The ___ for this medicine is 2 tablets per day.", "opts": ["treatment", "dosage", "symptom", "recovery"], "ans": 1, "exp": "dosage = liều lượng thuốc"}, {"q": "She is ___ well after the operation.", "opts": ["diagnosing", "treating", "recovering", "prescribing"], "ans": 2, "exp": "recovering = đang hồi phục"}, {"q": "A sore throat and runny nose are ___ of a cold.", "opts": ["treatments", "dosages", "surgeries", "symptoms"], "ans": 3, "exp": "symptoms = các triệu chứng"}]'::jsonb);
INSERT INTO topics (title, level, icon, theory, questions) VALUES ('Technology & Internet', 'B2', '💻', 'Từ vựng về công nghệ:

🔑 Thiết bị và internet:
• application/app (ứng dụng), download/upload (tải xuống/lên)
• bandwidth (băng thông), interface (giao diện), notification (thông báo)
• cybersecurity (an ninh mạng), algorithm (thuật toán)
• database (cơ sở dữ liệu), privacy (quyền riêng tư)
• artificial intelligence/AI (trí tuệ nhân tạo), cloud (điện toán đám mây)

✅ This app has a user-friendly interface.
✅ Make sure to protect your online privacy.
✅ The algorithm suggests content based on your activity.', '[{"q": "This website has a clean, user-friendly ___.", "opts": ["algorithm", "notification", "interface", "bandwidth"], "ans": 2, "exp": "interface = giao diện người dùng"}, {"q": "I keep getting ___ from apps on my phone.", "opts": ["algorithms", "notifications", "databases", "bandwidths"], "ans": 1, "exp": "notifications = thông báo từ ứng dụng"}, {"q": "Your ___ protects your personal information online.", "opts": ["bandwidth", "interface", "privacy", "algorithm"], "ans": 2, "exp": "privacy = quyền riêng tư"}, {"q": "Hackers attacked the company''s ___.", "opts": ["notification", "interface", "bandwidth", "cybersecurity"], "ans": 3, "exp": "cybersecurity = an ninh mạng"}, {"q": "The social media ___ decides what content you see.", "opts": ["interface", "algorithm", "database", "notification"], "ans": 1, "exp": "algorithm = thuật toán quyết định nội dung hiển thị"}, {"q": "Our ___ is slow — videos keep buffering.", "opts": ["algorithm", "database", "bandwidth", "application"], "ans": 2, "exp": "bandwidth = băng thông internet"}, {"q": "All customer records are stored in a secure ___.", "opts": ["algorithm", "interface", "notification", "database"], "ans": 3, "exp": "database = cơ sở dữ liệu"}, {"q": "You can ___ the file and save it to your computer.", "opts": ["upload", "notify", "interface", "bandwidth"], "ans": 0, "exp": "download (not upload — upload là gửi lên)"}, {"q": "___ is being used in healthcare to analyse medical data.", "opts": ["Bandwidth", "Database", "Artificial intelligence", "Interface"], "ans": 2, "exp": "Artificial intelligence (AI) = trí tuệ nhân tạo"}, {"q": "We store our data on the ___ instead of local servers.", "opts": ["algorithm", "cloud", "interface", "notification"], "ans": 1, "exp": "cloud = điện toán đám mây"}]'::jsonb);
INSERT INTO topics (title, level, icon, theory, questions) VALUES ('Environment & Nature', 'B2', '🌍', 'Từ vựng về môi trường:

🔑 Vấn đề môi trường:
• emissions (khí thải), carbon footprint (dấu chân carbon)
• deforestation (phá rừng), pollution (ô nhiễm), drought (hạn hán)
• habitat (môi trường sống), endangered (có nguy cơ tuyệt chủng)

🔑 Giải pháp:
• sustainable (bền vững), renewable energy (năng lượng tái tạo)
• biodiversity (đa dạng sinh học), ecosystem (hệ sinh thái)
• conservation (bảo tồn), recycle (tái chế)

✅ We need to reduce our carbon footprint.
✅ Deforestation threatens biodiversity.', '[{"q": "Factory ___ are a major cause of air pollution.", "opts": ["ecosystems", "emissions", "droughts", "habitats"], "ans": 1, "exp": "emissions = khí thải từ nhà máy"}, {"q": "Solar and wind power are types of ___ energy.", "opts": ["sustainable", "renewable", "endangered", "deforested"], "ans": 1, "exp": "renewable energy = năng lượng tái tạo"}, {"q": "___ destroys the homes of many animals.", "opts": ["Biodiversity", "Deforestation", "Conservation", "Drought"], "ans": 1, "exp": "deforestation = phá rừng, phá hủy môi trường sống"}, {"q": "This species is ___ — there are only 500 left.", "opts": ["sustainable", "renewable", "endangered", "recycled"], "ans": 2, "exp": "endangered = đang có nguy cơ tuyệt chủng"}, {"q": "The Amazon rainforest is an important ___.", "opts": ["emission", "drought", "ecosystem", "carbon footprint"], "ans": 2, "exp": "ecosystem = hệ sinh thái"}, {"q": "You can reduce your ___ by using public transport.", "opts": ["biodiversity", "habitat", "carbon footprint", "ecosystem"], "ans": 2, "exp": "carbon footprint = lượng CO2 thải ra từ hoạt động cá nhân"}, {"q": "Wildlife ___ protects animals from extinction.", "opts": ["pollution", "deforestation", "conservation", "emission"], "ans": 2, "exp": "conservation = bảo tồn thiên nhiên/động vật"}, {"q": "The lake ___ killed all the fish.", "opts": ["biodiversity", "conservation", "pollution", "drought"], "ans": 2, "exp": "pollution = ô nhiễm"}, {"q": "The region suffers from severe ___ — no rain for months.", "opts": ["emission", "drought", "deforestation", "ecosystem"], "ans": 1, "exp": "drought = hạn hán (thiếu mưa)"}, {"q": "Protecting ___ means saving many different species.", "opts": ["emissions", "biodiversity", "carbon footprint", "drought"], "ans": 1, "exp": "biodiversity = đa dạng sinh học"}]'::jsonb);
INSERT INTO grammar_lessons (title, level, icon, theory, questions) VALUES ('Advanced Modals', 'C1', '📘', 'Modal hoàn thành dùng để suy diễn hoặc bình luận về quá khứ:

✅ must have + V3: chắc chắn đã xảy ra (suy luận)
   VD: She must have left early — her coat is gone.

✅ can''t have + V3: không thể đã xảy ra
   VD: He can''t have done it — he was abroad.

✅ might/could have + V3: có thể đã xảy ra (không chắc)
   VD: She might have missed the bus.

✅ should have + V3: đáng lẽ phải làm (hối tiếc)
   VD: I should have studied harder.', '[{"q": "She looks exhausted. She ___ worked very late last night.", "opts": ["must have", "can''t have", "should have", "might not have"], "ans": 0, "exp": "must have + V3 = suy luận chắc chắn"}, {"q": "He ___ stolen it. He was in hospital at the time.", "opts": ["must have", "can''t have", "should have", "might have"], "ans": 1, "exp": "can''t have + V3 = không thể đã làm"}, {"q": "I ___ studied harder for the exam. I failed.", "opts": ["must have", "can''t have", "should have", "might have"], "ans": 2, "exp": "should have + V3 = đáng lẽ phải làm (hối tiếc)"}, {"q": "She''s not here yet. She ___ missed the train.", "opts": ["must have", "can''t have", "should have", "might have"], "ans": 3, "exp": "might have + V3 = có thể đã xảy ra (không chắc)"}, {"q": "You ___ told me! Now I''ve made a mistake.", "opts": ["must have", "can''t have", "should have", "might have"], "ans": 2, "exp": "should have = đáng lẽ phải làm"}, {"q": "The lights are off. They ___ gone to bed.", "opts": ["must have", "can''t have", "should have", "needn''t have"], "ans": 0, "exp": "must have = suy luận: chắc đã đi ngủ rồi"}, {"q": "She ___ passed — she studied for months.", "opts": ["can''t have", "must have", "needn''t have", "shouldn''t have"], "ans": 1, "exp": "must have = logic chắc chắn đã đậu"}, {"q": "He ___ taken the wrong road — he knows this city well.", "opts": ["must have", "can''t have", "should have", "could have"], "ans": 1, "exp": "can''t have = không hợp lý (anh ấy biết đường)"}, {"q": "___ I told you before? I''m sorry I forgot.", "opts": ["Must", "Should", "Can''t", "Might"], "ans": 1, "exp": "Should I have + V3? = Tôi đáng lẽ phải nói không?"}, {"q": "They ___ arrived by now — the flight landed 3 hours ago.", "opts": ["can''t have", "must have", "might have", "should have"], "ans": 1, "exp": "must have = suy luận có cơ sở"}]'::jsonb);
INSERT INTO grammar_lessons (title, level, icon, theory, questions) VALUES ('Inversion', 'C1', '📗', 'Đảo ngữ nhấn mạnh, thường dùng trong văn viết trang trọng:

✅ Never have I...: Never have I seen such beauty.
✅ Not only...but also: Not only did she win, but she also broke the record.
✅ Hardly...when: Hardly had I sat down when the phone rang.
✅ No sooner...than: No sooner had he left than it started raining.
✅ Only after/by/when: Only after the meeting did I understand.
✅ So + adj: So tired was she that she fell asleep instantly.
✅ Such + noun: Such was his anger that nobody spoke.', '[{"q": "Never ___ such a beautiful sunset.", "opts": ["I have seen", "have I seen", "I saw", "saw I"], "ans": 1, "exp": "Never + auxiliary + subject: Never have I seen"}, {"q": "Not only ___ the exam, but she also got the highest score.", "opts": ["she passed", "passed she", "did she pass", "has she pass"], "ans": 2, "exp": "Not only + did + S + V (đảo ngữ)"}, {"q": "Hardly ___ when the doorbell rang.", "opts": ["I sat down had", "had I sat down", "I had sat down", "sat down had I"], "ans": 1, "exp": "Hardly + had + S + V3 + when"}, {"q": "No sooner ___ than it began to snow.", "opts": ["we arrived had", "had we arrived", "we had arrived", "arrived we had"], "ans": 1, "exp": "No sooner + had + S + V3 + than"}, {"q": "Only after the lecture ___ the concept.", "opts": ["I understood", "understood I", "did I understand", "have I understood"], "ans": 2, "exp": "Only after + phrase + did + S + V"}, {"q": "So ___ that she fainted.", "opts": ["she was tired", "tired she was", "was she tired", "tired was she"], "ans": 2, "exp": "So + adj + was + S + that"}, {"q": "Under no circumstances ___ this door opened.", "opts": ["should be", "should this door be", "this door should be", "be this door"], "ans": 1, "exp": "Under no circumstances + modal + S + V"}, {"q": "Rarely ___ such dedication in a student.", "opts": ["I have seen", "have I seen", "I see", "do I see"], "ans": 3, "exp": "Rarely + do + S + V (hiện tại đơn)"}, {"q": "Not until midnight ___ home.", "opts": ["he came", "did he come", "came he", "he did come"], "ans": 1, "exp": "Not until + time + did + S + V"}, {"q": "Câu nào là đảo ngữ đúng?", "opts": ["Never I have been so scared.", "Hardly he had arrived when it rained.", "Not only did she sing, but she also danced.", "Only after I understood did the lecture."], "ans": 2, "exp": "Not only + did + S + V: Not only did she sing..."}]'::jsonb);
INSERT INTO grammar_lessons (title, level, icon, theory, questions) VALUES ('Gerunds vs Infinitives', 'C1', '📙', 'Động từ nguyên thể (to + V) và danh động từ (-ing) sau động từ:

✅ Luôn dùng gerund (-ing) sau: enjoy, avoid, finish, suggest, mind, consider, deny, admit, delay, practice, risk

✅ Luôn dùng infinitive (to + V) sau: want, need, decide, hope, plan, agree, refuse, offer, manage, expect, promise

✅ Có thể dùng cả hai (nghĩa thay đổi):
   stop + gerund = dừng hành động đang làm
   stop + infinitive = dừng lại để làm việc khác
   remember + gerund = nhớ đã làm (quá khứ)
   remember + infinitive = nhớ phải làm (tương lai)', '[{"q": "She enjoys ___ in the rain. (walk)", "opts": ["walk", "to walk", "walking", "walked"], "ans": 2, "exp": "enjoy + gerund: enjoys walking"}, {"q": "He decided ___ a new job. (find)", "opts": ["find", "finding", "to find", "found"], "ans": 2, "exp": "decide + infinitive: decided to find"}, {"q": "I avoid ___ junk food. (eat)", "opts": ["eat", "to eat", "eating", "ate"], "ans": 2, "exp": "avoid + gerund: avoid eating"}, {"q": "Would you mind ___ the window? (close)", "opts": ["close", "to close", "closing", "closed"], "ans": 2, "exp": "mind + gerund: mind closing"}, {"q": "She stopped ___ when she heard the news. (cry)", "opts": ["cry", "to cry", "crying", "cried"], "ans": 2, "exp": "stop + gerund = dừng hành động đang khóc"}, {"q": "He stopped ___ a newspaper. (buy) — dừng lại để mua", "opts": ["buy", "buying", "to buy", "bought"], "ans": 2, "exp": "stop + infinitive = dừng lại với mục đích khác"}, {"q": "I remember ___ her at the party last year. (meet)", "opts": ["meet", "to meet", "meeting", "met"], "ans": 2, "exp": "remember + gerund = nhớ đã từng gặp (quá khứ)"}, {"q": "Remember ___ the door before you leave. (lock)", "opts": ["lock", "locking", "to lock", "locked"], "ans": 2, "exp": "remember + infinitive = nhớ phải làm (việc cần làm)"}, {"q": "They managed ___ the project on time. (finish)", "opts": ["finish", "finishing", "to finish", "finished"], "ans": 2, "exp": "manage + infinitive: managed to finish"}, {"q": "She admitted ___ the money. (take)", "opts": ["take", "to take", "taking", "took"], "ans": 2, "exp": "admit + gerund: admitted taking"}]'::jsonb);
INSERT INTO grammar_lessons (title, level, icon, theory, questions) VALUES ('Mixed Conditionals', 'C1', '📒', 'Câu điều kiện hỗn hợp: kết hợp loại 2 và loại 3.

✅ Loại 3→2 (quá khứ ảnh hưởng hiện tại):
   If + past perfect, would + V
   VD: If I had studied medicine, I would be a doctor now.
   (Nếu trước đây học y → bây giờ là bác sĩ)

✅ Loại 2→3 (hiện tại ảnh hưởng quá khứ — ít phổ biến hơn):
   If + past simple, would have + V3
   VD: If I were braver, I would have spoken up.
   (Nếu tôi dũng cảm hơn → trước đây đã lên tiếng)

Mẹo: Nhìn vào thì của mệnh đề if và kết quả để xác định loại.', '[{"q": "If I ___ medicine, I would be a doctor now.", "opts": ["study", "studied", "had studied", "would study"], "ans": 2, "exp": "Mixed: If + past perfect (had studied) → would + V (now)"}, {"q": "If she ___ harder at school, she would have a better job now.", "opts": ["work", "worked", "had worked", "would work"], "ans": 2, "exp": "If + past perfect → would + V (present result)"}, {"q": "He ___ here now if he hadn''t left the country.", "opts": ["is", "was", "will be", "would be"], "ans": 3, "exp": "Mixed: If + past perfect → would + V (now)"}, {"q": "If I ___ braver, I would have spoken up at the meeting.", "opts": ["am", "was", "were", "had been"], "ans": 2, "exp": "Loại 2→3: If + past simple (were) → would have + V3"}, {"q": "If they ___ the contract, they would be successful now.", "opts": ["sign", "signed", "had signed", "would sign"], "ans": 2, "exp": "Past action → present result: had signed → would be"}, {"q": "She ___ a manager now if she hadn''t quit her job.", "opts": ["is", "was", "would be", "will be"], "ans": 2, "exp": "Mixed conditional result clause: would be (now)"}, {"q": "If he ___ a good education, he would have more opportunities now.", "opts": ["has", "had", "had had", "would have"], "ans": 2, "exp": "If + past perfect (had had) → would + V"}, {"q": "Đây là loại câu điều kiện gì? ''If you were more careful, you wouldn''t have made that mistake.''", "opts": ["Loại 1", "Loại 2", "Loại 3", "Hỗn hợp 2→3"], "ans": 3, "exp": "If + past simple → would have + V3 = Mixed 2→3"}, {"q": "If I ___ taller, I could have played basketball professionally.", "opts": ["am", "was", "were", "had been"], "ans": 2, "exp": "Tính cách hiện tại (were) → kết quả quá khứ (could have)"}, {"q": "They wouldn''t be in debt now if they ___ their money more carefully.", "opts": ["manage", "managed", "had managed", "would manage"], "ans": 2, "exp": "If + past perfect (had managed) → would + V (now)"}]'::jsonb);
INSERT INTO grammar_lessons (title, level, icon, theory, questions) VALUES ('Nominalisation', 'C2', '📘', 'Danh từ hóa (Nominalisation) là chuyển động từ/tính từ thành danh từ. Thường dùng trong văn học thuật/trang trọng.

✅ Động từ → danh từ:
   decide → decision, analyse → analysis
   develop → development, discover → discovery
   achieve → achievement, explain → explanation

✅ Tính từ → danh từ:
   important → importance, accurate → accuracy
   significant → significance, possible → possibility

✅ Lợi ích: câu ngắn gọn, khách quan hơn:
   ❌ They decided to close the factory.
   ✅ The decision to close the factory was made.', '[{"q": "The ___ of the experiment was published in a journal. (discover)", "opts": ["discovering", "discovered", "discovery", "discoverer"], "ans": 2, "exp": "discover → discovery (danh từ hóa)"}, {"q": "Their ___ of the problem led to a solution. (analyse)", "opts": ["analysing", "analysed", "analyst", "analysis"], "ans": 3, "exp": "analyse → analysis"}, {"q": "The ___ of new technology has changed the world. (develop)", "opts": ["developing", "developer", "development", "developed"], "ans": 2, "exp": "develop → development"}, {"q": "Her ___ of the results surprised everyone. (explain)", "opts": ["explaining", "explanation", "explained", "explainer"], "ans": 1, "exp": "explain → explanation"}, {"q": "The ___ of this project cannot be overstated. (important)", "opts": ["importance", "important", "importantly", "importation"], "ans": 0, "exp": "important → importance"}, {"q": "The ___ rate of the new vaccine is very high. (effective)", "opts": ["effectively", "effecting", "effectiveness", "effected"], "ans": 2, "exp": "effective → effectiveness"}, {"q": "She showed great ___ in achieving her goals. (determined)", "opts": ["determination", "determinated", "determinedly", "determine"], "ans": 0, "exp": "determined → determination"}, {"q": "Rewrite formally: ''Scientists discovered a new planet.'' →", "opts": ["A new planet was discovered.", "Scientists'' discovery of a new planet.", "The discovery of a new planet was made.", "A planet discovering was made."], "ans": 2, "exp": "Danh từ hóa: The discovery of... was made."}, {"q": "The ___ of both sides is essential for peace. (cooperate)", "opts": ["cooperating", "cooperation", "cooperated", "cooperatively"], "ans": 1, "exp": "cooperate → cooperation"}, {"q": "Her ___ at the competition was outstanding. (perform)", "opts": ["performing", "performer", "performed", "performance"], "ans": 3, "exp": "perform → performance"}]'::jsonb);
INSERT INTO grammar_lessons (title, level, icon, theory, questions) VALUES ('Discourse Markers', 'C2', '📗', 'Từ nối giúp diễn đạt mạch lạc, logic trong văn viết và nói:

✅ Bổ sung: furthermore, moreover, in addition, besides
✅ Đối lập: however, nevertheless, nonetheless, on the other hand, yet
✅ Kết quả: therefore, consequently, as a result, hence, thus
✅ Ví dụ: for instance, for example, such as, namely
✅ Nhượng bộ: although, even though, despite, in spite of
✅ Tóm tắt: in conclusion, to sum up, overall, in short
✅ Làm rõ: in other words, that is to say, to clarify', '[{"q": "The project was expensive. ___, it was completed on time.", "opts": ["Furthermore", "However", "Therefore", "For instance"], "ans": 1, "exp": "However = tuy nhiên (đối lập: đắt tiền nhưng đúng hạn)"}, {"q": "He didn''t study. ___, he failed the exam.", "opts": ["However", "Nevertheless", "Consequently", "Moreover"], "ans": 2, "exp": "Consequently = do đó (kết quả logic)"}, {"q": "She is talented. ___, she works very hard.", "opts": ["However", "Furthermore", "Therefore", "Despite"], "ans": 1, "exp": "Furthermore = hơn nữa (bổ sung điểm tốt)"}, {"q": "Many students struggle with grammar, ___ verb tenses.", "opts": ["for instance", "however", "therefore", "in conclusion"], "ans": 0, "exp": "for instance = ví dụ (đưa ra ví dụ cụ thể)"}, {"q": "___ the rain, they decided to go for a walk.", "opts": ["However", "Despite", "Therefore", "Furthermore"], "ans": 1, "exp": "Despite + noun phrase (không dùng Despite + clause)"}, {"q": "The economy is growing. ___, unemployment remains high.", "opts": ["Therefore", "Furthermore", "Nevertheless", "For instance"], "ans": 2, "exp": "Nevertheless = tuy vậy (đối lập nhượng bộ)"}, {"q": "The results were positive. ___, the study should be repeated.", "opts": ["However", "Therefore", "Nevertheless", "In other words"], "ans": 0, "exp": "However = tuy nhiên (cần thêm bằng chứng)"}, {"q": "___, the new policy has both advantages and disadvantages.", "opts": ["For instance", "To sum up", "Therefore", "However"], "ans": 1, "exp": "To sum up = tóm lại (kết luận)"}, {"q": "The plan is risky; ___, the rewards could be great.", "opts": ["therefore", "furthermore", "however", "namely"], "ans": 2, "exp": "however = tuy nhiên (mặc dù rủi ro vẫn có lợi ích)"}, {"q": "Câu nào dùng discourse marker đúng?", "opts": ["She failed. Despite, she tried again.", "He is smart. Furthermore, works hard.", "It rained. Nevertheless, we had fun.", "The test was hard. Therefore, but she passed."], "ans": 2, "exp": "Nevertheless = tuy vậy: mưa nhưng vẫn vui"}]'::jsonb);
INSERT INTO topics (title, level, icon, theory, questions) VALUES ('Education & Society', 'C1', '🎓', 'Từ vựng học thuật và xã hội:

🔑 Giáo dục đại học:
• curriculum (chương trình giảng dạy), pedagogy (phương pháp sư phạm)
• scholarship (học bổng), tuition fee (học phí), thesis (luận văn)
• undergraduate (sinh viên đại học), postgraduate (học sau đại học)

🔑 Vấn đề xã hội:
• equity (công bằng), discrimination (phân biệt đối xử)
• welfare (phúc lợi xã hội), legislation (lập pháp)
• accountability (trách nhiệm giải trình), disparity (bất bình đẳng)
• grassroots (cơ sở, phong trào từ dưới lên), bureaucracy (quan liêu)

✅ Education is key to reducing social disparity.
✅ New legislation aims to promote equity in schools.', '[{"q": "The school''s ___ includes science, arts, and languages.", "opts": ["pedagogy", "curriculum", "disparity", "legislation"], "ans": 1, "exp": "curriculum = chương trình học"}, {"q": "She received a full ___ and didn''t have to pay tuition.", "opts": ["disparity", "bureaucracy", "scholarship", "legislation"], "ans": 2, "exp": "scholarship = học bổng"}, {"q": "The report highlighted the ___ between rich and poor schools.", "opts": ["curriculum", "accountability", "disparity", "pedagogy"], "ans": 2, "exp": "disparity = sự chênh lệch, bất bình đẳng"}, {"q": "New ___ was passed to protect workers'' rights.", "opts": ["curriculum", "pedagogy", "disparity", "legislation"], "ans": 3, "exp": "legislation = luật được ban hành"}, {"q": "The ___ movement started locally before growing nationally.", "opts": ["bureaucratic", "grassroots", "legislative", "postgraduate"], "ans": 1, "exp": "grassroots = phong trào khởi nguồn từ cơ sở"}, {"q": "Racial ___ in hiring is illegal in many countries.", "opts": ["welfare", "disparity", "discrimination", "accountability"], "ans": 2, "exp": "discrimination = phân biệt đối xử"}, {"q": "The government increased ___ spending on healthcare.", "opts": ["bureaucracy", "welfare", "curriculum", "disparity"], "ans": 1, "exp": "welfare = phúc lợi xã hội"}, {"q": "Politicians must be held ___ for their decisions.", "opts": ["discriminatory", "grassroots", "accountable", "legislative"], "ans": 2, "exp": "accountable = có trách nhiệm giải trình"}, {"q": "She is doing her ___ research on climate change at university.", "opts": ["undergraduate", "grassroots", "postgraduate", "legislative"], "ans": 2, "exp": "postgraduate = sau đại học (nghiên cứu sinh)"}, {"q": "The complex ___ made it very hard to get the permit quickly.", "opts": ["disparity", "curriculum", "scholarship", "bureaucracy"], "ans": 3, "exp": "bureaucracy = hệ thống quan liêu, thủ tục phức tạp"}]'::jsonb);

-- Test bank
TRUNCATE test_bank RESTART IDENTITY CASCADE;
INSERT INTO test_bank (type, q, opts, ans, exp) VALUES ('grammar', 'She ___ to work by bus every day.', '["go", "goes", "going", "gone"]'::jsonb, 1, 'Present Simple + she → goes');
INSERT INTO test_bank (type, q, opts, ans, exp) VALUES ('grammar', 'I ___ my keys. Have you seen them?', '["lost", "have lost", "lose", "had lost"]'::jsonb, 1, 'Kết quả còn ở hiện tại → Present Perfect');
INSERT INTO test_bank (type, q, opts, ans, exp) VALUES ('grammar', 'If I ___ rich, I would travel the world.', '["am", "was", "were", "will be"]'::jsonb, 2, 'Type 2 Conditional: If + were');
INSERT INTO test_bank (type, q, opts, ans, exp) VALUES ('grammar', 'The letter ___ yesterday.', '["sent", "was sent", "is sent", "sends"]'::jsonb, 1, 'Bị động quá khứ: was sent');
INSERT INTO test_bank (type, q, opts, ans, exp) VALUES ('grammar', 'By the time she arrived, he ___ already left.', '["has", "have", "had", "did"]'::jsonb, 2, 'Past Perfect: had already left');
INSERT INTO test_bank (type, q, opts, ans, exp) VALUES ('grammar', 'She suggested ___ to the cinema.', '["to go", "go", "going", "gone"]'::jsonb, 2, 'suggest + V-ing: suggested going');
INSERT INTO test_bank (type, q, opts, ans, exp) VALUES ('grammar', 'I wish I ___ more time to study.', '["have", "had", "will have", "would have"]'::jsonb, 1, 'I wish + Past Simple để diễn tả điều ước hiện tại');
INSERT INTO test_bank (type, q, opts, ans, exp) VALUES ('grammar', 'The soup tastes ___.', '["well", "good", "nicely", "badly"]'::jsonb, 1, 'Linking verb ''taste'' + adjective: good');
INSERT INTO test_bank (type, q, opts, ans, exp) VALUES ('vocab', 'What is the meaning of ''AMBITIOUS''?', '["Lười biếng", "Có tham vọng", "Nhút nhát", "Tức giận"]'::jsonb, 1, 'Ambitious = có tham vọng, muốn thành công');
INSERT INTO test_bank (type, q, opts, ans, exp) VALUES ('vocab', '''The medicine had a ___ effect on the patient.''', '["beneficial", "ambiguous", "fastidious", "complacent"]'::jsonb, 0, 'Beneficial = có lợi, tốt');
INSERT INTO test_bank (type, q, opts, ans, exp) VALUES ('vocab', 'What does ''INEVITABLE'' mean?', '["Có thể tránh", "Không thể tránh", "Không quan trọng", "Có thể thay đổi"]'::jsonb, 1, 'Inevitable = không thể tránh khỏi');
INSERT INTO test_bank (type, q, opts, ans, exp) VALUES ('vocab', '''She is very ___ — she checks every detail twice.''', '["eloquent", "generous", "meticulous", "hesitant"]'::jsonb, 2, 'Meticulous = tỉ mỉ, cẩn thận từng chi tiết');
INSERT INTO test_bank (type, q, opts, ans, exp) VALUES ('vocab', '''Don''t ___ to call me if you need help.''', '["hesitate", "negotiate", "influence", "dedicate"]'::jsonb, 0, 'Hesitate = do dự. Don''t hesitate = đừng ngại');
INSERT INTO test_bank (type, q, opts, ans, exp) VALUES ('vocab', 'Which word means ''having a strong desire to succeed''?', '["generous", "persistent", "complacent", "benevolent"]'::jsonb, 1, 'Persistent = kiên trì, không bỏ cuộc');
INSERT INTO test_bank (type, q, opts, ans, exp) VALUES ('reading', '📖 "John has been learning English for three years. He studies every day and never misses a class. His teacher says he is one of the most diligent students she has ever taught."

How long has John been learning English?', '["One year", "Two years", "Three years", "Four years"]'::jsonb, 2, '''John has been learning English for three years.''');
INSERT INTO test_bank (type, q, opts, ans, exp) VALUES ('reading', '📖 "The new policy will be implemented next month. All employees are required to attend a training session. Those who cannot attend in person may join online."

What option is available for those who cannot attend in person?', '["They can skip", "They can join online", "They must attend later", "Send a representative"]'::jsonb, 1, '''Those who cannot attend in person may join online.''');
INSERT INTO test_bank (type, q, opts, ans, exp) VALUES ('reading', '📖 "Despite the heavy rain, the football match continued. The players showed remarkable determination and the home team eventually won 2-1."

What was the final score?', '["1-0", "2-0", "2-1", "1-1"]'::jsonb, 2, '''the home team eventually won 2-1''');